   562|
   563|export async function listSnapshots(limit: number = 50): Promise<SnapshotSummary[]> {
   564|  await ensureVaultDirs();
   565|  try {
   566|    const entries = await fs.readdir(SNAPSHOTS_DIR, { withFileTypes: true });
   567|    const results: SnapshotSummary[] = [];
   568|
   569|    for (const ent of entries.filter((e) => e.isDirectory())) {
   570|      const full = path.join(SNAPSHOTS_DIR, ent.name);
   571|      try {
   572|        const stat = await fs.stat(full);
   573|        let totalRows = 0;
   574|        let tableCount = 0;
   575|        try {
   576|          const meta = JSON.parse(await fs.readFile(path.join(full, 'meta.json'), 'utf8')) as SnapshotReport;
   577|          totalRows = meta.totalRows;
   578|          tableCount = meta.tableCount;
   579|        } catch { /* meta missing */ }
   580|        results.push({
   581|          snapshotId: ent.name,
   582|          path: `logs/audit/data-vault/snapshots/${ent.name}`,
   583|          sizeBytes: stat.size,
   584|          mtime: stat.mtime.toISOString(),
   585|          totalRows,
   586|          tableCount,
   587|        });
   588|      } catch { /* ignore */ }
   589|    }
   590|
   591|    return results.sort((a, b) => (a.mtime < b.mtime ? 1 : -1)).slice(0, limit);
   592|  } catch {
   593|    return [];
   594|  }
   595|}
