   597|export async function readSnapshot(snapshotId: string): Promise<SnapshotReport | null> {
   598|  const safe = snapshotId.replace(/[^a-zA-Z0-9_.-]/g, '');
   599|  if (!safe) return null;
   600|  try {
   601|    const metaPath = path.join(SNAPSHOTS_DIR, safe, 'meta.json');
   602|    const text = await fs.readFile(metaPath, 'utf8');
   603|    return JSON.parse(text) as SnapshotReport;
   604|  } catch {
