   608|
   609|export async function readSnapshotTable(snapshotId: string, table: string): Promise<{ rows: unknown[]; ok: boolean; error: string | null }> {
   610|  const safeId = snapshotId.replace(/[^a-zA-Z0-9_.-]/g, '');
   611|  const safeTable = table.replace(/[^a-zA-Z0-9_]/g, '');
   612|  if (!safeId || !safeTable) return { rows: [], ok: false, error: 'invalid_id_or_table' };
   613|  try {
   614|    const filePath = path.join(SNAPSHOTS_DIR, safeId, `${safeTable}.json`);
   615|    const text = await fs.readFile(filePath, 'utf8');
   616|    const rows = JSON.parse(text) as unknown[];
   617|    return { rows, ok: true, error: null };
   618|  } catch {
