   638|/**
   639| * Restore a snapshot back into Supabase. This OVERWRITES production data.
   640| * It requires explicit owner approval — the caller must pass `confirmed: true`
   641| * or the restore is refused.
   642| *
   643| * For each table, the restore:
   644| *   1. Reads the snapshot JSON from disk.
   645| *   2. Upserts all rows via the Supabase REST API (POST with upsert).
   646| *   3. Reports how many rows were written.
   647| *
   648| * The restore does NOT delete rows that exist in Supabase but not in the
   649| * snapshot — it only adds/updates rows from the snapshot. This is safer than
   650| * a full TRUNCATE+INSERT, which would cause downtime.
   651| */
   652|export async function restoreSnapshot(
   653|  snapshotId: string,
   654|  options: { confirmed?: boolean; tables?: string[] } = {},
   655|): Promise<RestoreReport> {
   656|  const startedAt = Date.now();
   657|  const timestamp = new Date().toISOString();
   658|
   659|  if (!options.confirmed) {
   660|    return {
   661|      snapshotId,
   662|      ok: false,
   663|      tablesRestored: 0,
   664|      totalRowsRestored: 0,
   665|      tables: [],
   666|      durationMs: Date.now() - startedAt,
   667|      timestamp,
   668|      requiresOwnerApproval: true,
   669|    };
   670|  }
   671|
   672|  const supa = resolveSupabase();
   673|  if (supa.missing.length > 0) {
   674|    return {
   675|      snapshotId,
   676|      ok: false,
   677|      tablesRestored: 0,
   678|      totalRowsRestored: 0,
   679|      tables: [],
   680|      durationMs: Date.now() - startedAt,
   681|      timestamp,
   682|      requiresOwnerApproval: true,
   683|    };
   684|  }
   685|
   686|  const snapshot = await readSnapshot(snapshotId);
   687|  if (!snapshot) {
   688|    return {
   689|      snapshotId,
   690|      ok: false,
   691|      tablesRestored: 0,
   692|      totalRowsRestored: 0,
   693|      tables: [],
   694|      durationMs: Date.now() - startedAt,
   695|      timestamp,
   696|      requiresOwnerApproval: true,
   697|    };
   698|  }
   699|
   700|  const tablesToRestore = options.tables ?? snapshot.tables.filter((t) => t.ok && t.rowCount > 0).map((t) => t.table);
   701|  const results: RestoreReport['tables'] = [];
   702|
   703|  for (const table of tablesToRestore) {
   704|    const { rows, ok, error } = await readSnapshotTable(snapshotId, table);
   705|    if (!ok || rows.length === 0) {
   706|      results.push({ table, ok: false, rowsAttempted: rows.length, rowsUpserted: 0, error: error ?? 'no_rows' });
   707|      continue;
   708|    }
   709|
   710|    try {
   711|      // Upsert via Supabase REST API. We use the Prefer: resolution=merge-duplicates
   712|      // header so existing rows (by PK) are updated, new rows are inserted.
   713|      const res = await fetch(`${supa.url}/rest/v1/${table}`, {
   714|        method: 'POST',
   715|        headers: {
   716|          apikey: supa.key,
   717|          Authorization: `Bearer ${supa.key}`,
   718|          'Content-Type': 'application/json',
   719|          Prefer: 'return=minimal,resolution=merge-duplicates',
   720|        },
   721|        body: JSON.stringify(rows),
   722|      });
   723|
   724|      if (!res.ok) {
   725|        const body = await res.text().catch(() => '');
   726|        results.push({
   727|          table,
   728|          ok: false,
   729|          rowsAttempted: rows.length,
   730|          rowsUpserted: 0,
   731|          error: `HTTP_${res.status}: ${body.slice(0, 200)}`,
   732|        });
   733|      } else {
   734|        results.push({
   735|          table,
   736|          ok: true,
   737|          rowsAttempted: rows.length,
   738|          rowsUpserted: rows.length,
   739|          error: null,
   740|        });
   741|      }
   742|    } catch (err) {
   743|      results.push({
   744|        table,
   745|        ok: false,
   746|        rowsAttempted: rows.length,
   747|        rowsUpserted: 0,
   748|        error: err instanceof Error ? err.message : 'network_error',
   749|      });
   750|    }
   751|  }
   752|
   753|  const tablesRestored = results.filter((r) => r.ok).length;
   754|  const totalRowsRestored = results.reduce((sum, r) => sum + r.rowsUpserted, 0);
   755|
   756|  return {
   757|    snapshotId,
   758|    ok: tablesRestored > 0,
   759|    tablesRestored,
   760|    totalRowsRestored,
   761|    tables: results,
   762|    durationMs: Date.now() - startedAt,
   763|    timestamp,
   764|    requiresOwnerApproval: true,
   765|  };
   766|}
