   877|// ---------------------------------------------------------------------------
   878|// Background scheduler
   879|// ---------------------------------------------------------------------------
   880|
   881|let vaultTimer: ReturnType<typeof setInterval> | null = null;
   882|
   883|export function startDataVaultScheduler(): void {
   884|  if (vaultTimer) return;
   885|  const enabled = (process.env.IVX_DATA_VAULT_SCHEDULER ?? 'on').toLowerCase();
   886|  if (enabled === 'off') return;
   887|
   888|  // Tick every 30 minutes — the schedule gate decides actual execution.
   889|  vaultTimer = setInterval(() => {
   890|    void (async () => {
   891|      try {
   892|        const state = await readState();
   893|        if (!state.config.enabled) return;
   894|
   895|        // Check if it's time for a snapshot
   896|        const lastAt = state.lastSnapshotAt ? Date.parse(state.lastSnapshotAt) : 0;
   897|        const due = Date.now() - lastAt >= state.config.intervalMs;
   898|        if (!due) return;
   899|
   900|        // Run data-loss detection first
   901|        await detectDataLoss();
   902|
   903|        // Then take the snapshot
   904|        await runDataVaultSnapshot();
   905|      } catch (err) {
   906|        console.warn('[IVXDataVault] scheduler tick failed:', err instanceof Error ? err.message : err);
   907|      }
   908|    })();
   909|  }, 30 * 60_000); // 30 minutes
   910|
   911|  if (typeof vaultTimer.unref === 'function') vaultTimer.unref();
   912|  console.log('[IVXDataVault] scheduler started — snapshots every 6h, data-loss detection active');
   913|}
